# constructor.py# Единый конструктор ссылок (с принтами для отладки)import jsonimport loggingimport refrom bot.bank import choose_countryfrom bot.parsers import parse_and_validatefrom bot.states import *from bot.states import STEP_CHOICE, STEP_INPUTfrom bot.types_config import CATEGORIES, LINK_TYPES, get_types_by_category, get_stepfrom bot.utils import get_db_connection, get_or_create_userfrom telegram import Update, InlineKeyboardButton, InlineKeyboardMarkupfrom telegram.ext import ContextTypes, ConversationHandler, CommandHandler, CallbackQueryHandler, MessageHandler, \    filterslogger = logging.getLogger(__name__)# ===== ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ =====async def get_page_id(context: ContextTypes.DEFAULT_TYPE, user_id: int) -> int:    """Получить page_id пользователя"""    conn = await get_db_connection()    try:        db_user = await get_or_create_user(conn, user_id, None, None, None)        page = await conn.fetchrow("SELECT id FROM pages WHERE user_id = $1", db_user['id'])        return page['id'] if page else None    finally:        await conn.close()def build_categories_keyboard() -> InlineKeyboardMarkup:    """Построить клавиатуру с категориями"""    keyboard = []    row = []    for i, (cat_id, cat_data) in enumerate(CATEGORIES.items()):        btn_text = cat_data['name']  # "💬 Мессенджеры"        callback = f"cat_{cat_id}"  # f"cat_messengers"        print(f"  🏷️  Кнопка: {btn_text} -> {callback}")        row.append(InlineKeyboardButton(btn_text, callback_data=callback))        if len(row) == 2:            keyboard.append(row)            row = []    if row:        keyboard.append(row)    keyboard.append([InlineKeyboardButton("◀️ Назад в меню", callback_data="back_to_main")])    return InlineKeyboardMarkup(keyboard)def build_types_keyboard(category: str) -> InlineKeyboardMarkup:    """Построить клавиатуру с типами ссылок для категории"""    types = get_types_by_category(category)    print(f"  🏷️  Типы в категории {category}: {list(types.keys())}")        keyboard = []    row = []        # Формируем кнопки типов по 2 в ряд    for type_id, type_data in types.items():        # Берем иконку из конфига, если есть        icon = type_data.get('icon_emoji') or type_data.get('icon', '🔹')        btn_text = f"{type_data['name']}"        callback = f"type_{type_id}"        row.append(InlineKeyboardButton(btn_text, callback_data=callback))        if len(row) == 2:            keyboard.append(row)            row = []    if row:        keyboard.append(row)    # ИСПРАВЛЕННАЯ ЛОГИКА КНОПКИ НАЗАД:    # Так как разделы "Биржи" и "Кошельки" объединены/удалены,    # кнопка назад всегда возвращает в выбор главных категорий (add_link)    back_callback = "add_link"    back_text = "◀️ Назад к категориям"    keyboard.append([InlineKeyboardButton(back_text, callback_data=back_callback)])        return InlineKeyboardMarkup(keyboard)# ===== ОБРАБОТЧИКИ =====async def start_constructor(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Точка входа: показать категории"""    print("\n" + "=" * 60)    print("🔧 Вызвана start_constructor\nНажата Добавить ссылку\n\n")        # В любом обработчике внутри ConversationHandler    print(f"  🔄 ТЕКУЩЕЕ СОСТОЯНИЕ ДИАЛОГА (которое ВОЗВРАЩАЕТСЯ): {context.user_data.get('_state', 'НЕТ СОСТОЯНИЯ')}")        # ===== ОЧИСТКА СТАРЫХ ДАННЫХ =====    keys_to_clear = ['category', 'link_type', 'step_index', 'collected_data', 'type_config']    for key in keys_to_clear:        if key in context.user_data:            del context.user_data[key]            print(f"  🧹 Очищено: {key}")    # =================================        query = update.callback_query    if query:        await query.answer()        print(f"  📩 callback_data: {query.data}")        user_id = query.from_user.id    else:        print(f"  📩 команда: /addlink")        user_id = update.message.from_user.id        print(f"  👤 user_id: {user_id}")    print(f"  📊 user_data keys: {list(context.user_data.keys())}")        # Проверка лимита ссылок (можно добавить позже)        text = "📁 **Выбери категорию** для новой ссылки:"    keyboard = build_categories_keyboard()        if query:        await query.edit_message_text(text, reply_markup=keyboard, parse_mode='Markdown')        print("  ✅ Отправлено меню категорий (edit)")    else:        await update.message.reply_text(text, reply_markup=keyboard, parse_mode='Markdown')        print("  ✅ Отправлено меню категорий (reply)")        print("=" * 60)    print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ:{WAIT_CONSTRUCTOR_CATEGORY}")    return WAIT_CONSTRUCTOR_CATEGORY# D:\aRabota\TelegaBoom\030_mylinkspace\bot\constructor.py# D:\aRabota\TelegaBoom\030_mylinkspace\bot\constructor.pyasync def handle_category(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Обработка выбора категории (Соцсети, Кошельки, Банки)"""    print("\n" + "=" * 60)    print("🔧 handle_category ВЫЗВАН\nНажата кнопка одной из категорий")        query = update.callback_query    await query.answer()        # Защита: проверяем, что это точно нажатие на категорию    if not query.data.startswith("cat_"):       print(f"  ⚠️ Это не категория: {query.data}")       return        category = query.data.replace("cat_", "")    print(f"  📩 callback_data: {query.data}")    print(f"  🏷️  Выбрана категория: {category}")        # Сохраняем категорию сразу    context.user_data['category'] = category    print(f"  💾 Сохранено в user_data['category'] = {category}")    # --- 1. ЛОГИКА ДЛЯ БАНКОВСКИХ ПЕРЕВОДОВ ---    if category == "transfers":        print(f"  🏦 Перенаправляем в банковский раздел")        from bot.bank import choose_country_from_constructor        state = await choose_country_from_constructor(update, context)        print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ (из банков): {state}")        return state        # --- 2. ЛОГИКА ДЛЯ КРИПТЫ, КОШЕЛЬКОВ И БИРЖ ---    # Добавил 'wallets' и 'stocks', чтобы они не падали при поиске в CATEGORIES    if category in ["crypto", "wallets", "stocks"]:        print(f"  💰 Перенаправляем в кошельковый раздел: {category}")        from bot.link_constructor import wallets_and_crypto_menu        state = await wallets_and_crypto_menu(update, context)        print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ (из финансового раздела): {state}")        return state    # --- 3. ОБЫЧНЫЙ КОНСТРУКТОР (Мессенджеры, Соцсети и др.) ---    cat_data = CATEGORIES.get(category, {})    if not cat_data:        print(f"  ❌ ОШИБКА: Категория {category} не найдена в CATEGORIES!")        await query.edit_message_text(f"❌ Ошибка: категория '{category}' не найдена.")        return 1200 # Возвращаем в выбор категорий    text = f"**{cat_data.get('name', category)}**\n\n{cat_data.get('description', '')}\n\n👇 **Выбери тип:**"    keyboard = build_types_keyboard(category)        await query.edit_message_text(text, reply_markup=keyboard, parse_mode='Markdown')        print(f"  ✅ Показаны типы для {category}")    print(f"  🔄 ДИАЛОГ ПЕРЕХОДИТ В СОСТОЯНИЕ: 1201")    print("=" * 60)        return 1201# D:\aRabota\TelegaBoom\030_mylinkspace\bot\constructor.pyasync def handle_type(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Обработка выбора типа ссылки (например, Telegram, WhatsApp, Binance)"""    print("\n" + "=" * 60)    print("🔧 handle_type ВЫЗВАН")        query = update.callback_query    await query.answer()        type_id = query.data.replace("type_", "")    print(f"  📩 callback_data: {query.data}")    print(f"  🏷️  Выбран тип: {type_id}")        # Инициализируем данные для новой ссылки    context.user_data['link_type'] = type_id    context.user_data['step_index'] = 0    context.user_data['collected_data'] = {}        # Получаем конфиг типа из LINK_TYPES    type_config = LINK_TYPES.get(type_id)        if not type_config:        print(f"  ❌ ОШИБКА: тип {type_id} не найден в LINK_TYPES!")        await query.edit_message_text("❌ Ошибка: конфигурация типа не найдена.")        # Возвращаем юзера к выбору типа в этой же категории        return WAIT_CONSTRUCTOR_TYPE        print(f"  📋 Конфиг типа загружен:")    print(f"    • Название: {type_config.get('name')}")    print(f"    • Шагов всего: {len(type_config.get('steps', []))}")        # Сохраняем конфиг в user_data, чтобы не искать его на каждом шаге    context.user_data['type_config'] = type_config        print(f"  🚀 Запуск первого шага (index=0)")    print("=" * 60)        # Вызываем функцию обработки шага.    # Она должна вернуть либо STEP_INPUT, либо STEP_CHOICE    new_state = await process_current_step(update, context)        print(f"  🔄 ПЕРЕХОД В СОСТОЯНИЕ: {new_state}")    return new_stateasync def process_current_step(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Обработать текущий шаг"""    print("\n" + "=" * 60)    print("🔧 process_current_step ВЫЗВАН")    print(f"  🔍 _state ДО: {context.user_data.get('_state')}")        step_index = context.user_data.get('step_index', 0)    type_config = context.user_data.get('type_config')        print(f"  📍 Текущий шаг index: {step_index}")    print(f"  📊 collected_data: {context.user_data.get('collected_data', {})}")        if not type_config:        print(f"  ❌ ОШИБКА: type_config не найден в user_data!")        print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {1200}")        return 1200 # WAIT_CONSTRUCTOR_CATEGORY        steps = type_config.get('steps', [])    print(f"  📋 Всего шагов: {len(steps)}")        # Все шаги пройдены - сохраняем    if step_index >= len(steps):        print(f"  ✅ Все шаги пройдены! Переход к сохранению")        print("=" * 60)        return await save_link(update, context)        step = steps[step_index]    print(f"  🎯 Шаг {step_index}: type={step['type']}, question='{step['question'][:50]}...'")        # ПОДГОТОВКА КЛАВИАТУРЫ    keyboard = []        if step['type'] == 'choice':        for opt in step['options']:            callback = f"choice_{opt['value']}"            print(f"    🟢 Вариант: {opt['label']} -> {callback}")            keyboard.append([InlineKeyboardButton(opt['label'], callback_data=callback)])        keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_types")])        text_to_send = step['question']        return_state = 1000 # STEP_CHOICE            elif step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:        text_to_send = step['question']        if 'example' in step:            text_to_send += f"\n\n📌 <b>Пример:</b> {step['example']}"            print(f"  💡 Пример: {step['example']}")                if step.get('optional'):            keyboard.append([InlineKeyboardButton("⏭️ Пропустить", callback_data="skip_step")])                keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous")])        return_state = 1001 # STEP_INPUT    # ОТПРАВКА СООБЩЕНИЯ (УНИВЕРСАЛЬНАЯ)    reply_markup = InlineKeyboardMarkup(keyboard) if keyboard else None        try:        if update.callback_query:            # Если пришли через кнопку - редактируем старое            await update.callback_query.edit_message_text(                text_to_send,                reply_markup=reply_markup,                parse_mode='HTML'            )            print(f"  ✅ Сообщение отредактировано (edit)")        else:            # Если пришли через текст (update.message) - отправляем новое            await update.message.reply_text(                text_to_send,                reply_markup=reply_markup,                parse_mode='HTML'            )            print(f"  ✅ Отправлено новое сообщение (reply)")                except Exception as e:        print(f"  ❌ ОШИБКА отправки в process_current_step: {e}")        # Если edit не сработал (например, текст тот же), пробуем просто отправить новое        await context.bot.send_message(            chat_id=update.effective_chat.id,            text=text_to_send,            reply_markup=reply_markup,            parse_mode='HTML'        )    print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {return_state}")    print("=" * 60)    return return_stateasync def handle_skip(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Пропустить опциональный шаг"""    print("\n" + "=" * 60)    print("⏭️ handle_skip ВЫЗВАН")        query = update.callback_query    await query.answer()        step_index = context.user_data.get('step_index', 0)    type_config = context.user_data.get('type_config')    steps = type_config.get('steps', [])        print(f"  📍 Пропускаем шаг {step_index}")        # Сохраняем None для пропущенного поля    step = steps[step_index]    field = step.get('field')    if field:        context.user_data['collected_data'][field] = None        print(f"  💾 Поле {field} = None")                # Если пропустили шаг с заголовком (title)        if field == 'title':            choice = context.user_data['collected_data'].get('choice')            type_name = type_config.get('name', '')                        # Маппинг выбора на русское название            type_map = {                'personal': 'Личный аккаунт',                'channel': 'Канал',                'group': 'Группа',                'bot': 'Бот',                'profile': 'Профиль',                'page': 'Страница',                'public': 'Публичная страница',                'invite': 'Приглашение'            }                        if choice and choice in type_map:                # Сохраняем автоматическое название                context.user_data['collected_data']['title'] = f"{type_name} {type_map[choice]}"                print(f"  💾 Авто-название: {type_name} {type_map[choice]}")        # Переходим к следующему шагу    context.user_data['step_index'] = step_index + 1        # Если это был последний шаг - сохраняем    if step_index + 1 >= len(steps):        print(f"  📍 Это был последний шаг, сохраняем")                # ИСПОЛЬЗУЕМ query.message, А НЕ update.message!        class FakeQuery:            def __init__(self, message):                self.message = message                        async def edit_message_text(self, text, **kwargs):                return await self.message.reply_text(text, **kwargs)                fake_query = FakeQuery(query.message)        return await save_link_with_query(update, context, fake_query)        print(f"  🔄 Переходим к шагу {step_index + 1}")    print("=" * 60)        return await process_current_step(update, context)async def handle_choice(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Обработка выбора из вариантов с защитой от IndexError"""    print("\n" + "=" * 60)    print("🔧 handle_choice ВЫЗВАН")        query = update.callback_query    await query.answer()        choice = query.data.replace("choice_", "")    step_index = context.user_data.get('step_index', 0)    type_config = context.user_data.get('type_config')        if not type_config:        print("  ❌ ОШИБКА: type_config не найден")        return 1200 # Возврат к выбору категории        # Сохраняем выбор пользователя    steps = type_config.get('steps', [])    step = steps[step_index]    field = step.get('field', 'choice')        if 'collected_data' not in context.user_data:        context.user_data['collected_data'] = {}    context.user_data['collected_data'][field] = choice    print(f"  💾 Сохранено: collected_data['{field}'] = '{choice}'")    # СОХРАНЯЕМ ПОЛНУЮ КОПИЮ ОРИГИНАЛЬНОГО КОНФИГА (если еще нет)    # Это наш "золотой стандарт", откуда мы будем выдергивать вопросы    if 'full_type_config' not in context.user_data:        import copy        context.user_data['full_type_config'] = copy.deepcopy(type_config)        print(f"  💾 Создана полная копия конфига")    full_steps = context.user_data['full_type_config'].get('steps', [])    type_name = type_config.get('name')    # --- БЕЗОПАСНАЯ ЛОГИКА ВК ---    if type_name == "VK":        # Ожидаемая структура full_steps: 0:title, 1:choice, 2:profile_id, 3:public_id, 4:group_id        new_steps = [full_steps[0], full_steps[1]] # Всегда оставляем заголовок и выбор                if choice == 'profile':            # Профиль — это всегда шаг 2            new_steps.append(full_steps[2])                elif choice == 'public':            # Копируем базовый текстовый шаг (индекс 2) и меняем ему вопрос из индекса 3            public_step = full_steps[2].copy()            q = full_steps[3]['question'] if len(full_steps) > 3 else "Введите ID публичной страницы:"            public_step.update({'field': 'public_id', 'question': q})            new_steps.append(public_step)                    elif choice == 'group':            # Копируем базовый текстовый шаг и меняем вопрос из индекса 4            group_step = full_steps[2].copy()            q = full_steps[4]['question'] if len(full_steps) > 4 else "Введите ID группы:"            group_step.update({'field': 'group_id', 'question': q})            new_steps.append(group_step)                    type_config['steps'] = new_steps        context.user_data['step_index'] = 2    # --- БЕЗОПАСНАЯ ЛОГИКА FACEBOOK ---    elif type_name == "Facebook":        if choice == 'profile':            type_config['steps'] = [full_steps[0], full_steps[1], full_steps[2]]        elif choice == 'page':            s_title = full_steps[2].copy()            q_t = full_steps[3]['question'] if len(full_steps) > 3 else "Название страницы:"            s_title.update({'field': 'page_title', 'question': q_t})                        s_user = full_steps[2].copy()            q_u = full_steps[4]['question'] if len(full_steps) > 4 else "Username страницы:"            s_user.update({'field': 'page_username', 'question': q_u})                        type_config['steps'] = [full_steps[0], full_steps[1], s_title, s_user]        elif choice == 'group':            s_title = full_steps[2].copy()            q_t = full_steps[5]['question'] if len(full_steps) > 5 else "Название группы:"            s_title.update({'field': 'group_title', 'question': q_t})                        s_user = full_steps[2].copy()            q_u = full_steps[6]['question'] if len(full_steps) > 6 else "Username группы:"            s_user.update({'field': 'group_username', 'question': q_u})                        type_config['steps'] = [full_steps[0], full_steps[1], s_title, s_user]        context.user_data['step_index'] = 2    # --- БЕЗОПАСНАЯ ЛОГИКА TELEGRAM ---    elif type_name == "Telegram":        type_map = {'personal': 2, 'channel': 3, 'group': 4, 'bot': 5}        target_idx = type_map.get(choice, 2)                if target_idx < len(full_steps):            type_config['steps'] = [full_steps[0], full_steps[1], full_steps[target_idx]]            context.user_data['step_index'] = 1            labels = {'personal': 'Профиль', 'channel': 'Канал', 'group': 'Группа', 'bot': 'Бот'}            context.user_data['default_title'] = f"Telegram {labels.get(choice, '')}"        else:            context.user_data['step_index'] = step_index + 1    # --- ОСТАЛЬНЫЕ ТИПЫ ---    else:        next_step = None        for opt in step.get('options', []):            if opt['value'] == choice:                next_step = opt.get('next_step')                break        context.user_data['step_index'] = next_step if next_step is not None else step_index + 1    print(f"  🔄 Переходим к шагу {context.user_data['step_index']}")    print(f"  📊 Новый конфиг содержит {len(type_config.get('steps', []))} шагов")    print("=" * 60)            return await process_current_step(update, context)async def handle_input(update: Update, context: ContextTypes.DEFAULT_TYPE):    print("🟢🟢🟢🟢🟢 handle_input (constructor) ВЫЗВАНА! 🟢🟢🟢🟢🟢")        """Обработка текстового ввода"""    print("\n" + "=" * 60)    print("🔧 handle_input ВЫЗВАН")        message = update.message    if not message or not message.text:        print(f"  ❌ Нет текста в сообщении")        return STEP_INPUT        text = message.text.strip()    user_id = message.from_user.id    print(f"  👤 user_id: {user_id}")    print(f"  📩 ввод: '{text}'")        step_index = context.user_data.get('step_index', 0)    type_config = context.user_data.get('type_config')        print(f"  📍 Текущий шаг index: {step_index}")        if not type_config:        print(f"  ❌ ОШИБКА: type_config не найден!")        await message.reply_text("❌ Ошибка, начни заново /addlink")                print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")        return WAIT_CONSTRUCTOR_CATEGORY        steps = type_config.get('steps', [])    if step_index >= len(steps):        print(f"  ❌ ОШИБКА: step_index {step_index} вне диапазона (всего шагов {len(steps)})")        print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")        return WAIT_CONSTRUCTOR_CATEGORY        step = steps[step_index]    field = step.get('field', 'value')        # ===== ПРОВЕРКА ДЛИНЫ =====    if step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:        max_len = step.get('max_length', 255)        if len(text) > max_len:            # Определяем название поля для сообщения об ошибке            field_label = step.get('question', 'значение').replace('<b>', '').replace('</b>', '')[:30]                        error_msg = (                f"❌ **Слишком длинное {field_label}!**\n\n"                f"📏 Максимальная длина: **{max_len}** символов\n"                f"✏️ Вы ввели: **{len(text)}** символов\n\n"                f"👉 Пожалуйста, сократите и отправьте **снова**"            )                        print(f"  ❌ Ошибка длины: {len(text)} > {max_len}")            await message.reply_text(                error_msg,                parse_mode='Markdown',                reply_markup=InlineKeyboardMarkup([[                    InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous"),                    InlineKeyboardButton("❌ Отмена", callback_data="add_link")                ]])            )                        # Остаемся на том же шаге            return STEP_INPUT    # ===========================        # Сохраняем введенное значение    context.user_data['collected_data'][field] = text    print(f"  💾 Сохранено: collected_data['{field}'] = '{text}'")        # Переходим к следующему шагу    context.user_data['step_index'] = step_index + 1    print(f"  🔄 Переходим к шагу {step_index + 1}")        # Если следующий шаг - тоже ввод, отправляем подтверждение    if step_index + 1 < len(steps):        await message.reply_text("✅ Принято! Далее...")        print(f"  ✅ Отправлено подтверждение")        print("=" * 60)        # Создаем объект, похожий на CallbackQuery    class FakeQuery:        def __init__(self, message):            self.message = message            self.data = None                async def answer(self):            pass                async def edit_message_text(self, text, **kwargs):            return await self.message.reply_text(text, **kwargs)        fake_query = FakeQuery(update.message)        # Передаем фейковый query    return await process_current_step_with_query(update, context, fake_query)async def process_current_step_with_query(update: Update, context: ContextTypes.DEFAULT_TYPE, fake_query):    """Версия process_current_step с готовым query и проверкой длины"""    print("\n" + "=" * 60)    print("🔧 process_current_step_with_query ВЫЗВАН")        # ===== ПРОВЕРЯЕМ, НЕ ПРИШЛО ЛИ СООБЩЕНИЕ С ДЛИННЫМ ТЕКСТОМ =====    if update.message and update.message.text:        print(f"\n🔍🔍🔍 ПОЛУЧЕНО СООБЩЕНИЕ: {update.message.text[:30]}...")                step_index = context.user_data.get('step_index', 0)        type_config = context.user_data.get('type_config')                print(f"📊 step_index: {step_index}")        print(f"📊 type_config: {type_config.get('name') if type_config else 'None'}")                if type_config:            steps = type_config.get('steps', [])            print(f"📊 steps length: {len(steps)}")                        if step_index < len(steps):                step = steps[step_index]                print(f"📊 step type: {step['type']}")                print(f"📊 step field: {step.get('field')}")                print(f"📊 step max_length: {step.get('max_length')}")                                # Если это текстовый шаг - проверяем длину                if step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:                    print(f"✅ Шаг опознан как текстовый!")                    value = update.message.text                    max_len = step.get('max_length', 255)                                        print(f"📏 Длина введенного текста: {len(value)}")                    print(f"📏 Максимальная длина: {max_len}")                                        if len(value) > max_len:                        print(f"❌ Длина превышена! Должна быть ошибка!")                                                # ОПРЕДЕЛЯЕМ field_label                        field_label = step.get('question', 'значение').replace('<b>', '').replace('</b>', '')[:30]                                                # СОЗДАЕМ error_msg                        error_msg = (                            f"❌ **Слишком длинное {field_label}!**\n\n"                            f"📏 Максимальная длина: **{max_len}** символов\n"                            f"✏️ Вы ввели: **{len(value)}** символов\n\n"                            f"👉 Пожалуйста, сократите и отправьте **снова**"                        )                                                # Отправляем сообщение об ошибке                        await update.message.reply_text(                            error_msg,                            parse_mode='Markdown',                            reply_markup=InlineKeyboardMarkup([[                                InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous"),                                InlineKeyboardButton("❌ Отмена", callback_data="add_link")                            ]])                        )                                                # Остаемся на том же шаге                        print(f"  ❌ Ошибка длины: {len(value)} > {max_len}")                        return STEP_INPUT        step_index = context.user_data.get('step_index', 0)    type_config = context.user_data.get('type_config')        print(f"  📍 Текущий шаг index: {step_index}")    print(f"  📊 collected_data: {context.user_data.get('collected_data', {})}")        if not type_config:        print(f"  ❌ ОШИБКА: type_config не найден!")                print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")        return WAIT_CONSTRUCTOR_CATEGORY        steps = type_config.get('steps', [])    print(f"  📋 Всего шагов: {len(steps)}")        if step_index >= len(steps):        print(f"  ✅ Все шаги пройдены! Переход к сохранению")        print("=" * 60)        return await save_link_with_query(update, context, fake_query)        step = steps[step_index]    print(f"  🎯 Шаг {step_index}: type={step['type']}, question='{step['question'][:50]}...'")        if step['type'] == 'choice':        # Показываем варианты выбора        keyboard = []        for opt in step['options']:            callback = f"choice_{opt['value']}"            print(f"    🟢 Вариант: {opt['label']} -> {callback}")            keyboard.append([InlineKeyboardButton(opt['label'], callback_data=callback)])                keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_types")])                await fake_query.edit_message_text(            step['question'],            reply_markup=InlineKeyboardMarkup(keyboard),            parse_mode='HTML'        )        print(f"  ✅ Отправлен choice-шаг")        print("=" * 60)        return STEP_CHOICE        elif step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:        # Просим ввести текст        text = step['question']        if 'example' in step:            text += f"\n\n📌 *Пример:* {step['example']}"            print(f"  💡 Пример: {step['example']}")                # Добавляем информацию о максимальной длине        max_len = step.get('max_length', 255)        text += f"\n\n📏 *Максимум {max_len} символов*"                # СОЗДАЕМ КЛАВИАТУРУ        keyboard = []                # Добавляем кнопку "Пропустить" если шаг опциональный        if step.get('optional'):            keyboard.append([InlineKeyboardButton("⏭️ Пропустить", callback_data="skip_step")])                keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous")])                await fake_query.edit_message_text(            text,            reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,            parse_mode='HTML'        )        print(f"  ✅ Отправлен input-шаг (ожидание ввода)")        print("=" * 60)                print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {STEP_INPUT}")        return STEP_INPUTasync def save_link(update: Update, context: ContextTypes.DEFAULT_TYPE):    """    Финальное сохранение: упаковывает данные в pay_details и выводит полный отчет пользователю.    """    print("\n" + "=" * 60)    print("💾 save_link ВЫЗВАН (Информативный отчет)")        if update.callback_query:        query = update.callback_query        user_id = query.from_user.id    else:        class FakeQuery:            def __init__(self, message): self.message = message            async def edit_message_text(self, text, **kwargs):                return await self.message.reply_text(text, **kwargs)        query = FakeQuery(update.message)        user_id = update.message.from_user.id        user_data = context.user_data    type_config = user_data.get('type_config')    collected = user_data.get('collected_data', {})    link_type = user_data.get('link_type', 'custom')        if not type_config:        await query.edit_message_text("❌ Ошибка сессии, начните заново.")        return ConversationHandler.END    # ВАЖНО: Получаем сформированную ссылку из парсера    generated_url, error = await parse_and_validate(link_type, collected)        if error:        await query.edit_message_text(f"❌ {error}")        return ConversationHandler.END    conn = await get_db_connection()    try:        page_id = await get_page_id(context, user_id)        if not page_id:            await query.edit_message_text("❌ Ошибка: страница не найдена.")            return ConversationHandler.END        # --- ПОДГОТОВКА ДАННЫХ ---        title = collected.get('title') or type_config.get('name', 'Ссылка')        # Теперь записываем сгенерированную ссылку, а не пустоту        url = generated_url if generated_url else ""        icon = type_config.get('icon', '')        category = type_config.get('category', 'wallets')        is_exchange = type_config.get('is_exchange', False)                # Формируем pay_details (исключаем технические поля)        exclude_report = [            'title', 'step_index', 'phone_display', 'phone_clean',            'id_display', 'id_clean', 'username_display', 'email_display'        ]        pay_details_dict = {k: v for k, v in collected.items() if k not in exclude_report}        pay_details_json = json.dumps(pay_details_dict, ensure_ascii=False)        max_order = await conn.fetchval(            "SELECT COALESCE(MAX(sort_order), 0) FROM links WHERE page_id = $1", page_id        )        # --- ЗАПИСЬ В БАЗУ (url теперь попадает в $3) ---        await conn.execute("""            INSERT INTO links (                page_id, title, url, icon, sort_order,                link_type, pay_details, is_exchange, category, is_active            ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, true)        """, page_id, title[:255], url, icon[:100], max_order + 1, link_type, pay_details_json, is_exchange, category)                # --- ФОРМИРОВАНИЕ ПОДРОБНОГО ОТЧЕТА ---        page_username = await conn.fetchval("SELECT username FROM pages WHERE id = $1", page_id)        page_link = f"botolink.pro/{page_username}"                details_text = ""        field_names = {            "wallet_address": "💰 Адрес",            "network": "🌐 Сеть",            "uid": "🆔 UID",            "email": "📧 Email",            "id": "🆔 ID",            "phone": "📞 Телефон",            "username": "👤 Username"        }                for key, value in pay_details_dict.items():            if value:                label = field_names.get(key, key.capitalize())                details_text += f"• <b>{label}:</b> <code>{value}</code>\n"        category_label = "📈 Биржа" if is_exchange else "👛 Кошелек"        success_message = (            f"✅ <b>Карточка успешно добавлена!</b>\n\n"            f"📌 <b>Инфо:</b>\n"            f"• <b>Название:</b> {title}\n"            f"• <b>Тип:</b> {category_label}\n"            f"{details_text}"            f"• <b>Раздел:</b> <code>{category}</code>\n\n"            f"🌐 <b>Твоя страница:</b>\n"            f"👉 <a href='https://{page_link}'><code>{page_link}</code></a>\n"            f"<i>Ссылка сохранена и готова к работе.</i>"        )        await query.edit_message_text(            success_message,            reply_markup=InlineKeyboardMarkup([                [                    InlineKeyboardButton("📋 Управление", callback_data="links"),                    InlineKeyboardButton("➕ Добавить ещё", callback_data="add_link")                ],                [InlineKeyboardButton("🏠 Главное меню", callback_data="main_menu")]            ]),            parse_mode='HTML',            disable_web_page_preview=True        )    except Exception as e:        print(f"❌ ОШИБКА БД: {e}")        await query.edit_message_text(f"❌ Ошибка сохранения: {e}")    finally:        await conn.close()    for key in ['type_config', 'collected_data', 'step_index', 'link_type']:        user_data.pop(key, None)        user_data['ignore_next_text'] = True    return ConversationHandler.ENDasync def save_link_with_query(update: Update, context: ContextTypes.DEFAULT_TYPE, fake_query):    """Сохранить ссылку в БД (версия с fake_query)"""    print("\n" + "=" * 60)    print("💾 save_link_with_query ВЫЗВАН")        type_config = context.user_data.get('type_config')    collected = context.user_data.get('collected_data', {})    link_type = context.user_data.get('link_type')        if update.callback_query:        user_id = update.callback_query.from_user.id    else:        user_id = update.message.from_user.id        # ===== 1. ВАЛИДАЦИЯ И ПАРСИНГ (Получаем URL) =====    url, error = await parse_and_validate(link_type, collected)        if error:        print(f"  ❌ Ошибка валидации: {error}")        await fake_query.edit_message_text(error)        context.user_data['step_index'] = max(0, context.user_data.get('step_index', 1) - 1)        return await process_current_step_with_query(update, context, fake_query)        # ===== 2. ФОРМИРОВАНИЕ НАЗВАНИЯ =====    title = collected.get('title') or type_config.get('name', 'Ссылка')        if not collected.get('channel_name') and collected.get('channel_input'):        channel_input = collected.get('channel_input')        match = re.search(r'(?:youtube\.com/|@)([^/]+)', channel_input)        channel_name = match.group(1) if match else channel_input.replace('@', '')        collected['channel_name'] = channel_name.capitalize()        # ===== 3. СОХРАНЕНИЕ В БД =====    conn = await get_db_connection()    try:        db_user = await get_or_create_user(conn, user_id, None, None, None)        page = await conn.fetchrow("SELECT id, username FROM pages WHERE user_id = $1", db_user['id'])                if not page:            await fake_query.edit_message_text("❌ Ошибка: страница не найдена")            return ConversationHandler.END                page_id = page['id']        page_username = page['username']                max_order = await conn.fetchval(            "SELECT COALESCE(MAX(sort_order), 0) FROM links WHERE page_id = $1", page_id        )                # Исключаем технические поля из JSON        exclude_fields = [            'title', 'choice', 'step_index', 'type_config',            'link_type', 'phone_display', 'id_display',            'phone_clean', 'id_clean', 'username_display', 'email_display'        ]        pay_details = {k: v for k, v in collected.items() if k not in exclude_fields}                # Фикс для Max        if link_type == "max" and 'phone' in pay_details:            pay_details['id'] = pay_details.pop('phone')                final_url = url if url else ""        pay_details_json = json.dumps(pay_details, ensure_ascii=False) if pay_details else None                await conn.execute("""            INSERT INTO links            (page_id, title, url, icon, sort_order, link_type, category, pay_details, is_active)            VALUES ($1, $2, $3, $4, $5, $6, $7, $8, true)        """, page_id, title[:255], final_url, type_config.get('icon', '')[:100],           max_order + 1, link_type, type_config.get('category'), pay_details_json)                page_link = f"https://botolink.pro/{page_username}"        category_name = CATEGORIES.get(type_config.get('category'), {}).get('name', 'Разное')                success_message = (            f"✅ <b>{title[:50]}</b> успешно добавлена!\n\n"            f"🌐 <b>Твоя страница:</b>\n"            f"👉 <a href='{page_link}'>{page_link}</a>\n"            f"Раздел: «{category_name}»"        )                await fake_query.edit_message_text(            success_message,            reply_markup=InlineKeyboardMarkup([                [                    InlineKeyboardButton("📋 Управление", callback_data="links"),                    InlineKeyboardButton("➕ Добавить ещё", callback_data="add_link")                ],                [InlineKeyboardButton("🏠 Главное меню", callback_data="start")]            ]),            parse_mode='HTML',            disable_web_page_preview=True        )            except Exception as e:        print(f"  ❌ ОШИБКА: {e}")        await fake_query.edit_message_text("❌ Ошибка при сохранении")    finally:        await conn.close()        context.user_data.clear()    return ConversationHandler.END        async def process_current_step_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Версия process_current_step для сообщений (без query)"""    print("\n" + "=" * 60)    print("🔧 process_current_step_callback (для сообщений)")        # Искусственно создаем callback_query для переиспользования функции    class FakeQuery:        def __init__(self, message):            self.message = message            self.data = None                async def edit_message_text(self, text, **kwargs):            print(f"  📝 FakeQuery.edit_message_text: '{text[:50]}...'")            return await self.message.reply_text(text, **kwargs)                async def answer(self):            pass        fake_query = FakeQuery(update.message)        print("=" * 60)        print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {STEP_INPUT}")    return await process_current_step_with_query(update, context, fake_query)  # ← ВОТ ТУТ ИСПРАВЛЕНИЕ# КУДА: bot/constructor.py# ФУНКЦИЯ: save_link (полностью)# D:\aRabota\TelegaBoom\030_mylinkspace\bot\constructor.pyfrom bot.states import WAIT_CONSTRUCTOR_CATEGORY # Проверь, что импорт есть вверху файлаasync def back_to_categories(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Вернуться к выбору категории"""    print("\n" + "=" * 60)    print("🔙 back_to_categories ВЫЗВАН")        query = update.callback_query    await query.answer()        print(f"  📩 callback_data: {query.data}")    print(f"  🧹 Очистка user_data")        # Полностью чистим данные, чтобы старые банковские выборы не всплыли    context.user_data.clear()        print("=" * 60)        # 1. Отрисовываем меню категорий (Соцсети, Кошельки и т.д.)    await start_constructor(update, context)        # 2. ЯВНО возвращаем стейт начала конструктора    # Без этого return бот будет думать, что ты всё ещё в банках!    return WAIT_CONSTRUCTOR_CATEGORYasync def back_to_types(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Вернуться к выбору типа в текущей категории (с учетом подразделов)"""    print("\n" + "=" * 60)    print("🔙 back_to_types ВЫЗВАН")        query = update.callback_query    await query.answer()        category = context.user_data.get('category')    print(f"  🏷️  Текущая категория: {category}")        if category:        # ПОЛНОСТЬЮ ОЧИЩАЕМ ДАННЫЕ ТЕКУЩЕГО ПРОЦЕССА        keys_to_clear = ['step_index', 'collected_data', 'type_config', 'original_link_type']        for key in keys_to_clear:            context.user_data.pop(key, None)        print(f"  🧹 Очищены данные шагов для: {category}")        # 1. Логика для подразделов (Кошельки / Биржи)        if category in ["wallets", "stocks"]:            if category == "wallets":                text = "👛 <b>Выберите криптовалюту:</b>\n\nНиже список доступных кошельков для ваших адресов."            else:                text = "🏦 <b>Выберите биржу:</b>\n\nВыберите платформу для ввода реквизитов (UID, Pay)."                        # Генерируем клавиатуру именно для подразделов            keyboard = build_types_keyboard(category)                        # Меняем кнопку "Назад" в этой клавиатуре на возврат в cat_crypto            # Чтобы не выбрасывало в самое начало категорий            for row in keyboard.inline_keyboard:                for button in row:                    if button.callback_data == "add_link":                        button.text = "◀️ Назад"                        button.callback_data = "cat_crypto"            await query.edit_message_text(text, reply_markup=keyboard, parse_mode='HTML')            return 1201        # 2. Стандартная логика для остальных категорий (Соцсети и т.д.)        cat_data = CATEGORIES.get(category, {})        text = f"{cat_data.get('icon', '📁')} <b>{cat_data.get('name', category)}</b>\n\n{cat_data.get('description', '')}\n\n👇 <b>Выбери тип:</b>"                keyboard = build_types_keyboard(category)                await query.edit_message_text(text, reply_markup=keyboard, parse_mode='HTML')        print(f"  ✅ Показаны типы для {category}")        print("=" * 60)                return WAIT_CONSTRUCTOR_TYPE        return await back_to_categories(update, context)async def cancel_constructor(update: Update, context: ContextTypes.DEFAULT_TYPE):    """Отмена создания ссылки"""    print("\n" + "=" * 60)    print("❌ cancel_constructor ВЫЗВАН")        query = update.callback_query    if query:        await query.answer()        print(f"  📩 callback_data: {query.data}")        print(f"  🧹 Очистка user_data")    context.user_data.clear()        print("=" * 60)        # СРАЗУ В ГЛАВНОЕ МЕНЮ!    from bot.handlers import start_handler    return await start_handler(update, context)